export type AgentStatus = (typeof AGENT_STATUS_VALUES)[number];

export interface ApiError {
  code: string;
  message: string;
}

export interface ApiErrorResponse {
  error: ApiError;
}

export const ROUTES = {
  authToken: "/api/auth/token",
  authLogout: "/api/auth/logout",
  authExample: "/api/example",
